import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}
// DO NOT EDIT types below — auto-generated from the data contract





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
  conditionIcon: string;
}

// Controller: business logic, wire hooks, data transformations
// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  // Map weather condition to emoji icon
  const conditionIcon = useMemo(() => {
    const condition = props.condition.toLowerCase();
    if (condition.includes('sunny') || condition.includes('clear')) return '☀️';
    if (condition.includes('cloudy') || condition.includes('overcast')) return '☁️';
    if (condition.includes('rainy') || condition.includes('rain')) return '🌧️';
    if (condition.includes('snow')) return '❄️';
    if (condition.includes('storm') || condition.includes('thunder')) return '⛈️';
    if (condition.includes('windy')) return '💨';
    if (condition.includes('fog') || condition.includes('mist')) return '🌫️';
    return '🌤️';
  }, [props.condition]);

  return {
    city: props.city,
    temperature: props.temperature,
    condition: props.condition,
    humidity: props.humidity,
    windSpeed: props.windSpeed,
    unit: props.unit,
    forecast: props.forecast,
    conditionIcon,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  // add any UI-only state here (tabs, accordions, scroll position, etc.)

  return (
    <Container maxWidth="xl" padding={"var(--ggui-spacing-6, 24px)"}>
      <Stack gap={"var(--ggui-spacing-4, 16px)"}>
        {/* HEADER WITH CITY */}
        <Stack gap={"var(--ggui-spacing-2, 8px)"}>
          <Heading level={1}>{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current Weather
          </Text>
        </Stack>

        {/* MAIN WEATHER CARD */}
        <Card shadow="md" padding={"var(--ggui-spacing-6, 24px)"} radius="lg">
          <Stack gap={"var(--ggui-spacing-4, 16px)"}>
            {/* TEMPERATURE & CONDITION */}
            <Stack direction="horizontal" align="center" gap={"var(--ggui-spacing-6, 24px)"}>
              <Stack align="center" justify="center">
                <Icon name={props.conditionIcon} size={80} />
              </Stack>
              <Stack gap={"var(--ggui-spacing-2, 8px)"}>
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.temperature}°{props.unit}
                </Text>
                <Text size="lg" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {props.condition}
                </Text>
              </Stack>
            </Stack>

            <Divider orientation="horizontal" margin={"var(--ggui-spacing-2, 8px)"} />

            {/* HUMIDITY & WIND */}
            <Stack direction="horizontal" justify="between" gap={"var(--ggui-spacing-4, 16px)"}>
              <Stack gap={"var(--ggui-spacing-1, 4px)"}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.humidity}%
                </Text>
              </Stack>
              <Stack gap={"var(--ggui-spacing-1, 4px)"}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.windSpeed} m/s
                </Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST STRIP */}
        <Stack gap={"var(--ggui-spacing-2, 8px)"}>
          <Heading level={4}>5-Day Forecast</Heading>
          <Stack direction="horizontal" gap={"var(--ggui-spacing-2, 8px)"} wrap>
            {props.forecast.map((day, index) => (
              <Card
                key={index}
                shadow="sm"
                padding={"var(--ggui-spacing-3, 12px)"}
                radius="md"
                style={{
                  flex: '1 1 calc(20% - 7px)',
                  minWidth: '100px',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                }}
              >
                <Stack gap={"var(--ggui-spacing-1, 4px)"} align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                    {day.day || `Day ${index + 1}`}
                  </Text>
                  <Icon name={day.icon || '🌤️'} size={32} />
                  <Stack direction="horizontal" gap={"var(--ggui-spacing-1, 4px)"} justify="center">
                    <Text size="sm" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {day.high != null ? `${day.high}°${props.unit}` : 'N/A'}
                    </Text>
                    <Text size="sm" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {day.low != null ? `${day.low}°${props.unit}` : 'N/A'}
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            ))}
           </Stack>
         </Stack>
       </Stack>
     </Container>
   );

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

