// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  currentStep: number;
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onSatisfactionChange: (value: number) => void;
  onFeatureToggle: (feature: string) => void;
  onCommentsChange: (value: string) => void;
  onNext: () => void;
  onBack: () => void;
  onSubmit: () => void;
  nameError: string;
  emailError: string;
  satisfactionLabels: string[];
  featureOptions: string[];
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const submit = useAction<ActionSubmitPayload>('submit');

  // Validation
  const nameError = name.trim() === '' && currentStep >= 1 ? 'Name is required' : '';
  const emailError = useMemo(() => {
    if (currentStep < 1) return '';
    if (email.trim() === '') return 'Email is required';
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) return 'Please enter a valid email address';
    return '';
  }, [email, currentStep]);

  const isStep1Valid = name.trim() !== '' && email.trim() !== '' && !emailError;
  const isStep2Valid = satisfaction > 0;
  const isStep3Valid = true; // features step has no required fields

  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !isStep2Valid) return;
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  }, [name, email, satisfaction, features, comments, submit]);

  return {
    currentStep,
    name,
    email,
    satisfaction,
    features,
    comments,
    onNameChange: setName,
    onEmailChange: setEmail,
    onSatisfactionChange: (value: number) => setSatisfaction(value),
    onFeatureToggle: handleFeatureToggle,
    onCommentsChange: setComments,
    onNext: handleNext,
    onBack: handleBack,
    onSubmit: handleSubmit,
    nameError,
    emailError,
    satisfactionLabels: props.satisfactionLabels,
    featureOptions: props.featureOptions,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const totalSteps = 5;
  const progressPercent = (props.currentStep / totalSteps) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* PROGRESS BAR */}
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {props.currentStep} of {totalSteps}
          </Text>
          <Progress value={props.currentStep} max={totalSteps} size="md" variant="default" />
        </Stack>

        {/* STEP CONTENT */}
        <Card padding="var(--ggui-spacing-6, 24px)" shadow="sm" border>
          {props.currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={props.name}
                onChange={props.onNameChange}
                required
                error={props.nameError}
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email address"
                value={props.email}
                onChange={props.onEmailChange}
                required
                error={props.emailError}
              />
            </Stack>
          )}

          {props.currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                How satisfied are you overall?
              </Text>
              <RadioGroup
                label=""
                value={String(props.satisfaction)}
                onChange={(value: string) => props.onSatisfactionChange(parseInt(value, 10))}
                options={(props.satisfactionLabels || []).map((label, index) => ({
                  value: String(index + 1),
                  label: `${index + 1} - ${label}`,
                }))}
                direction="vertical"
              />
            </Stack>
          )}

          {props.currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Which features interest you?
              </Text>
              <Stack gap="var(--ggui-spacing-3, 12px)">
                {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={props.features.includes(feature)}
                    onChange={() => props.onFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

           {props.currentStep === 4 && (
             <Stack gap="var(--ggui-spacing-4, 16px)">
               <Heading level={3}>Comments</Heading>
               <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                 Any additional feedback?
               </Text>
               <TextArea
                 label="Comments"
                 placeholder="Enter your comments here..."
                 value={props.comments}
                 onChange={props.onCommentsChange}
                 maxLength={500}
                 showCount
                 rows={6}
               />
             </Stack>
           )}

           {props.currentStep === 5 && (
             <Stack gap="var(--ggui-spacing-4, 16px)">
               <Heading level={3}>Review Your Answers</Heading>
               <Stack gap="var(--ggui-spacing-4, 16px)" align="start">
                 <Box>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                   <Text variant="body">{props.name}</Text>
                 </Box>
                 <Box>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                   <Text variant="body">{props.email}</Text>
                 </Box>
                 <Box>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                    <Text variant="body">{props.satisfaction} - {(props.satisfactionLabels || [])[props.satisfaction - 1] || 'Unknown'}</Text>
                 </Box>
                 <Box>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Selected Features</Text>
                   <Text variant="body">{props.features.length > 0 ? props.features.join(', ') : 'None selected'}</Text>
                 </Box>
                 <Box>
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                   <Text variant="body">{props.comments || 'No comments provided'}</Text>
                 </Box>
               </Stack>
             </Stack>
            )}
         </Card>

         {/* NAVIGATION BUTTONS */}
         <Row gap="var(--ggui-spacing-2, 8px)" justify="end" align="center">
           {props.currentStep > 1 && (
             <Button variant="ghost" onClick={props.onBack}>
               Back
             </Button>
           )}
           {props.currentStep < totalSteps && (
             <Button
               variant="primary"
               onClick={props.onNext}
               disabled={
                 (props.currentStep === 1 && (!!props.nameError || !!props.emailError)) ||
                 (props.currentStep === 2 && !props.satisfaction)
               }
             >
               Next
             </Button>
           )}
           {props.currentStep === totalSteps && (
             <Button variant="primary" onClick={props.onSubmit}>
               Submit
             </Button>
           )}
         </Row>
       </Stack>
     </Container>
   );
 }

 // DO NOT EDIT render — it connects Controller to View
 export default function render(props: Props) {
   const viewProps = ComponentController(props);
   return <ComponentView {...viewProps} />;
 }

