// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string; priority?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate: (action: string, taskId: string, data: { column?: string; title?: string; priority?: string }) => void;
  onMoveTask: (taskId: string, toColumn: string) => void;
  onEditTask: (taskId: string, title: string, priority: string) => void;
  onCreateTask: (title: string, priority: string, column: string, assignee?: string) => void;
  totalTasks: number;
  completedTasks: number;
  getPriorityBadgeVariant: (priority?: string) => 'error' | 'warning' | 'info' | 'success' | 'default' | 'primary' | 'secondary';
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [localTasks, setLocalTasks] = useState(props.tasks);

  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Sync tasks from stream updates
  useEffect(() => {
    if (taskChanged.latest) {
      const updatedTask = taskChanged.latest.task;
      if (updatedTask?.id) {
        if (taskChanged.latest.action === 'delete') {
          setLocalTasks((prev) => prev.filter((t) => t.id !== updatedTask.id));
        } else {
          setLocalTasks((prev) => {
            const idx = prev.findIndex((t) => t.id === updatedTask.id);
            if (idx >= 0) {
              const updated = [...prev];
              updated[idx] = { ...updated[idx], ...updatedTask };
              return updated;
            }
            return [...prev, updatedTask];
          });
        }
      }
    }
  }, [taskChanged.latest]);

  // Sync local tasks from props
  useEffect(() => {
    setLocalTasks(props.tasks);
  }, [props.tasks]);

  const onMoveTask = useCallback(
    (taskId: string, toColumn: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t))
      );
      taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
    },
    [taskUpdate]
  );

  const onEditTask = useCallback(
    (taskId: string, title: string, priority: string) => {
      const currentTask = localTasks.find((t) => t.id === taskId);
      const column = currentTask?.column || 'todo';
      setLocalTasks((prev) =>
        prev.map((t) =>
          t.id === taskId ? { ...t, title, priority: priority as 'low' | 'medium' | 'high' } : t
        )
      );
      taskUpdate({ action: 'edit', taskId, data: { title, priority, column } });
    },
    [taskUpdate, localTasks]
  );

  const onCreateTask = useCallback(
    (title: string, priority: string, column: string, assignee?: string) => {
      const newId = `task-${Date.now()}`;
      const newTask = { id: newId, title, priority: priority as 'low' | 'medium' | 'high', assignee, column };
      setLocalTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newId, data: { column, title, priority } });
    },
    [taskUpdate]
  );

  const onTaskUpdate = useCallback(
    (action: string, taskId: string, data: { column?: string; title?: string; priority?: string }) => {
      if (action === 'move' && data.column) {
        onMoveTask(taskId, data.column);
      } else if (action === 'edit' && (data.title || data.priority)) {
        onEditTask(taskId, data.title || '', data.priority || 'medium');
      }
    },
    [onMoveTask, onEditTask]
  );

  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter((t) => t.column === 'done').length;

  const getPriorityBadgeVariant = (priority?: string): 'error' | 'warning' | 'info' | 'success' | 'default' | 'primary' | 'secondary' => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'info';
      default:
        return 'default';
    }
  };

  return {
    tasks: localTasks,
    columns: props.columns,
    onTaskUpdate,
    onMoveTask,
    onEditTask,
    onCreateTask,
    totalTasks,
    completedTasks,
    getPriorityBadgeVariant,
  };
}

