// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  // Filter elements by search query (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter((el) => {
      const name = el.name?.toLowerCase() ?? '';
      const symbol = el.symbol?.toLowerCase() ?? '';
      return name.includes(query) || symbol.includes(query);
    });
  }, [searchQuery, props.elements]);

  // Get unique categories and map to colors
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // Category color mapping using design tokens
  const categoryColors: Record<string, string> = useMemo(() => {
    const colorPalette = [
      'var(--ggui-color-primary-600)',
      'var(--ggui-color-success-600)',
      'var(--ggui-color-warning-600)',
      'var(--ggui-color-error-600)',
      'var(--ggui-color-info-600)',
      'var(--ggui-color-primary-500)',
      'var(--ggui-color-success-500)',
      'var(--ggui-color-warning-500)',
    ];
    const colors: Record<string, string> = {};
    categories.forEach((cat, idx) => {
      colors[cat] = colorPalette[idx % colorPalette.length];
    });
    return colors;
  }, [categories]);

  // DO NOT EDIT wire hooks below — auto-generated from the data contract


  return {
    elements: props.elements,
    searchQuery,
    onSearchChange: setSearchQuery,
    selectedElement,
    onElementClick: setSelectedElement,
    filteredElements,
    categoryColors,
    categories,
  };
}

