}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: Array<{key?: string; value?: string}>; reviews?: Array<{author?: string; rating?: number; text?: string; date?: string}> };
  onAddToCart: () => void;
  quantity: number;
  setQuantity: (qty: number) => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  isOutOfStock: boolean;
  stockStatus: string;
  stockBadgeVariant: 'success' | 'warning' | 'error';
  formattedPrice: string;
  renderStars: (rating: number) => React.ReactNode;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  const isOutOfStock = (props.product?.stock ?? 0) === 0;
  const stockStatus = (props.product?.stock ?? 0) > 5 ? 'In Stock' : (props.product?.stock ?? 0) > 0 ? 'Low Stock' : 'Out of Stock';
  const stockBadgeVariant: 'success' | 'warning' | 'error' = (props.product?.stock ?? 0) > 5 ? 'success' : (props.product?.stock ?? 0) > 0 ? 'warning' : 'error';

  const formattedPrice = useMemo(() => {
    if (!props.product?.price) return '$0.00';
    const currencySymbol = props.product.currency === 'USD' ? '$' : props.product.currency === 'EUR' ? '€' : props.product.currency === 'GBP' ? '£' : '$';
    return currencySymbol + props.product.price.toFixed(2);
  }, [props.product?.price, props.product?.currency]);

  const renderStars = (rating: number) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Icon key={i} name={i <= Math.round(rating) ? 'star' : 'star'} size={16} color={i <= Math.round(rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'} />
      );
    }
    return <Row gap={4} align="center">{stars}</Row>;
  };

  const handleAddToCart = useCallback(() => {
    if (props.product?.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product?.id, quantity, addToCart]);

  const handleQuantityChange = useCallback((qty: number) => {
    const maxStock = props.product?.stock ?? 0;
    const newQty = Math.max(1, Math.min(qty, maxStock));
    setQuantity(newQty);
  }, [props.product?.stock]);

  return {
    product: props.product,
    onAddToCart: handleAddToCart,
    quantity,
    setQuantity: handleQuantityChange,
    activeTab,
    setActiveTab,
    isOutOfStock,
    stockStatus,
    stockBadgeVariant,
    formattedPrice,
    renderStars,
  };
}

