          {/* Product Image Placeholder */}
          <Box
            padding="var(--ggui-spacing-6, 24px)"
            background="var(--ggui-color-primary-100, #e0f2fe)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{ minWidth: '280px', width: '280px', height: '280px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack align="center" justify="center" gap="var(--ggui-spacing-2, 8px)">
              <Icon name="image" size={48} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" align="center">{props.product?.name || 'Product Image'}</Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4, 16px)" style={{ flex: 1 }}>
            <Heading level={2}>{props.product?.name || 'Untitled Product'}</Heading>

            {/* Price */}
            <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">{props.formattedPrice}</Text>

            {/* Rating */}
            <Row gap={8} align="center">
              {props.renderStars(props.product?.rating || 0)}
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">({props.product?.reviewCount || 0} reviews)</Text>
            </Row>

            {/* Stock Status Badge */}
            <Badge variant={props.stockBadgeVariant} size="md">{props.stockStatus}</Badge>
          </Stack>
        </Stack>

        <Divider />

        {/* MIDDLE SECTION: Tab Navigation */}
        <Tabs
          items={[
            { key: 'description', label: 'Description', content: renderDescription() },
            { key: 'specifications', label: 'Specifications', content: renderSpecifications() },
            { key: 'reviews', label: 'Reviews', content: renderReviews() },
          ]}
          activeKey={props.activeTab}
          onChange={props.setActiveTab}
          variant="line"
        />

        <Divider />

        {/* BOTTOM SECTION: Quantity Selector + Add to Cart */}
        <Stack gap="var(--ggui-spacing-4, 16px)" align="start">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
            <Text variant="label">Quantity:</Text>
            <Button variant="outline" size="sm" onClick={() => props.setQuantity(props.quantity - 1)} disabled={props.quantity <= 1}>−</Button>
            <Text variant="body" style={{ minWidth: '30px', textAlign: 'center' }}>{props.quantity}</Text>
            <Button variant="outline" size="sm" onClick={() => props.setQuantity(props.quantity + 1)} disabled={props.quantity >= (props.product?.stock || 0)}>+</Button>
          </Stack>

          <Button
            variant="primary"
            size="lg"
            fullWidth
            onClick={props.onAddToCart}
            disabled={props.isOutOfStock}
          >
            {props.isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

