                        {(() => { const d = new Date(msg.timestamp); return !isNaN(d.getTime()) ? d.toLocaleTimeString() : 'Invalid time'; })()}
                      </Text>
                    )}
                  </Box>
                );
              })}

              {/* TYPING INDICATOR */}
              {props.typingIndicator?.active && props.typingIndicator?.sender && (
                <Box paddingX={12} paddingY={8} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {props.typingIndicator.sender} is typing
                    <span style={{ animation: 'blink 1.4s step-end infinite' }}>.</span>
                    <span style={{ animation: 'blink 1.4s step-end 0.2s infinite' }}>.</span>
                    <span style={{ animation: 'blink 1.4s step-end 0.4s infinite' }}>.</span>
                  </Text>
                </Box>
              )}

              <div ref={messagesEndRef} />
            </Stack>
          </Box>

