          <Divider margin={0} />
          <Box paddingX={24} paddingY={16}>
            <Stack direction="horizontal" gap={12} align="end">
              <TextArea
                label="Message"
                value={inputText}
                onChange={setInputText}
                onKeyDown={handleKeyDown}
                placeholder="Type your message (Enter to send, Shift+Enter for newline)"
