              />
              <Button
                variant="primary"
                size="md"
                onClick={handleSendClick}
                disabled={!inputText.trim()}
              >
                Send
              </Button>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

