// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  lastUpdated: string;
  highlightedSymbols: Set<string>;
  marketStatus: string;
  isLoading: boolean;
  onStockClick: (symbol: string) => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState(new Date().toLocaleTimeString());
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const [marketStatus, setMarketStatus] = useState<string>('closed');
  const [isLoading, setIsLoading] = useState(false);
  const highlightTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatusStream = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Merge price updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const updated = priceUpdate.latest;
      setDisplayStocks((prev) =>
        prev.map((stock) =>
          stock.symbol === updated.symbol
            ? { ...stock, price: updated.price ?? stock.price, change: updated.change ?? stock.change, changePercent: updated.changePercent ?? stock.changePercent }
            : stock
        )
      );
      // Highlight the updated stock
      if (updated.symbol) {
        setHighlightedSymbols((prev) => new Set(prev).add(updated.symbol));
        // Clear highlight after 1 second
        if (highlightTimeoutRef.current) clearTimeout(highlightTimeoutRef.current);
        highlightTimeoutRef.current = setTimeout(() => {
          setHighlightedSymbols((prev) => {
            const next = new Set(prev);
            next.delete(updated.symbol!);
            return next;
          });
        }, 1000);
      }
      // Update timestamp
      setLastUpdated(new Date().toLocaleTimeString());
    }
  }, [priceUpdate.latest]);

  // Handle market status updates
  useEffect(() => {
    if (marketStatusStream.latest) {
      setMarketStatus(marketStatusStream.latest.status || 'closed');
    }
  }, [marketStatusStream.latest]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (highlightTimeoutRef.current) clearTimeout(highlightTimeoutRef.current);
    };
  }, []);

  const handleStockClick = useCallback((symbol: string) => {
    // Click handler for interactive cards
  }, []);

  return {
    stocks: displayStocks,
    lastUpdated,
    highlightedSymbols,
    marketStatus,
    isLoading,
    onStockClick: handleStockClick,
  };
}

// Sub-component for individual stock card
function StockCard({ stock, isHighlighted, onClick }: { stock: { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }; isHighlighted: boolean; onClick: () => void }) {
  const isPositive = (stock.change ?? 0) >= 0;
  const borderColor = isPositive ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-error-500, #ef4444)';
  const textColor = isPositive ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
  const arrowIcon = isPositive ? '▲' : '▼';

  return (
    <Card
      as={Clickable}
      onClick={onClick}
      shadow="md"
      padding="var(--ggui-spacing-4, 16px)"
      border
      style={{
        borderColor: borderColor,
        borderWidth: '2px',
        backgroundColor: isHighlighted ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)',
        animation: isHighlighted ? 'ggui-stock-flash 0.6s ease-in-out' : 'none',
        cursor: 'pointer',
      }}
    >
      <Stack gap="var(--ggui-spacing-2, 8px)">
        <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {stock.name || 'Unknown Company'}
        </Text>
        <Heading level={3} color="var(--ggui-color-onSurface, #18181b)" style={{ marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
          {stock.symbol || 'N/A'}
        </Heading>
        <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)" weight="bold">
          ${stock.price?.toFixed(2) ?? '0.00'}
        </Text>
        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
          <Text color={textColor} weight="semibold">
            {isPositive ? '+' : ''}{stock.change?.toFixed(2) ?? '0.00'}
          </Text>
          <Text color={textColor} weight="semibold">
            {arrowIcon} {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
