// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  currentStep: 1 | 2 | 3;
  formData: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: 'light' | 'dark';
  };
  errors: {
    name?: string;
    email?: string;
  };
  onNext: () => void;
  onBack: () => void;
  onFieldChange: (field: string, value: unknown) => void;
  onComplete: () => void;
  avatarOptions: string[];
  roleOptions: string[];
  canNext: boolean;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions?.length ? props.avatarOptions[0] : ''),
    role: props.initialProfile.role || (props.roleOptions?.length ? props.roleOptions[0] : ''),
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: (props.initialProfile.theme as 'light' | 'dark') || 'light',
  });
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  const complete = useAction<ActionCompletePayload>('complete');

  // Validation functions
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: { name?: string; email?: string } = {};
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Invalid email format';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const canNext = useMemo(() => {
    if (currentStep === 1) {
      return formData.name.trim() !== '' && validateEmail(formData.email);
    }
    return true;
  }, [currentStep, formData.name, formData.email]);

  const onFieldChange = useCallback((field: string, value: unknown) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'name' || field === 'email') {
      setErrors((prev) => ({ ...prev, [field]: undefined }));
    }
  }, []);

  const onNext = useCallback(() => {
    if (currentStep === 1) {
      if (!validateStep1()) return;
    }
    if (currentStep < 3) {
      setCurrentStep((prev) => (prev + 1) as 1 | 2 | 3);
    }
  }, [currentStep, formData.name, formData.email]);

  const onBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => (prev - 1) as 1 | 2 | 3);
    }
  }, [currentStep]);

  const onComplete = useCallback(() => {
    if (validateStep1()) {
      complete(formData);
    }
  }, [formData, complete]);

  return {
    currentStep,
    formData,
    errors,
    onNext,
    onBack,
    onFieldChange,
    onComplete,
    avatarOptions: props.avatarOptions,
    roleOptions: props.roleOptions,
    canNext,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const progressPercent = ((props.currentStep - 1) / 2) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* HEADER: Step indicator and progress bar */}
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Stack direction="horizontal" align="center" justify="between">
            <Heading level={2}>Profile Setup</Heading>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {props.currentStep} of 3
            </Text>
          </Stack>
          <Progress value={progressPercent} max={100} variant="default" size="md" />
        </Stack>

        {/* CONTENT: Dynamic step rendering */}
        <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            {props.currentStep === 1 && <Step1 {...props} />}
            {props.currentStep === 2 && <Step2 {...props} />}
            {props.currentStep === 3 && <Step3 {...props} />}
          </Stack>
        </Card>

        {/* FOOTER: Navigation buttons */}
        <Row gap="var(--ggui-spacing-4, 16px)" justify="between">
          <Button
            variant="ghost"
            onClick={props.onBack}
            disabled={props.currentStep === 1}
          >
            Go Back
          </Button>
          {props.currentStep < 3 ? (
            <Button
              variant="primary"
              onClick={props.onNext}
              disabled={!props.canNext}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={props.onComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

